#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <errno.h>

char* read_and_write_csv(const char *filename) {
    FILE *in = fopen(filename, "r");
    if (!in) {
        char *msg = malloc(256);
        snprintf(msg, 256, "%s", strerror(errno));
        return msg;
    }
    fseek(in, 0, SEEK_END);
    long size = ftell(in);
    fseek(in, 0, SEEK_SET);
    char *buffer = malloc(size + 1);
    if (!buffer) {
        fclose(in);
        char *msg = malloc(256);
        snprintf(msg, 256, "Memory allocation failed");
        return msg;
    }
    fread(buffer, 1, size, in);
    buffer[size] = '\0';
    fclose(in);

    FILE *out = fopen(filename, "w");
    if (!out) {
        free(buffer);
        char *msg = malloc(256);
        snprintf(msg, 256, "%s", strerror(errno));
        return msg;
    }
    fwrite(buffer, 1, size, out);
    fclose(out);
    free(buffer);
    char *msg = malloc(8);
    strcpy(msg, "Success");
    return msg;
}

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    char filename[256];
    for (int i = 0; i < T; ++i) {
        scanf("%s", filename);
        char *res = read_and_write_csv(filename);
        printf("%s\n", res);
        free(res);
    }
    return 0;
}

