import sys, csv

def read_and_write_csv(filename):
    try:
        with open(filename, newline='') as f:
            reader = csv.reader(f)
            rows = list(reader)
        with open(filename, 'w', newline='') as f:
            writer = csv.writer(f)
            writer.writerows(rows)
        return "Success"
    except Exception as e:
        return str(e)

def main():
    data = sys.stdin.read().splitlines()
    if not data:
        return
    t = int(data[0].strip())
    for i in range(1, t + 1):
        filename = data[i].strip()
        print(read_and_write_csv(filename))

if __name__ == "__main__":
    main()

